import pickle

def save_object(obj, filepath):
    with open(filepath, 'wb') as f:
        pickle.dump(obj, f, protocol=pickle.HIGHEST_PROTOCOL)

def load_object(filepath):
    with open(filepath, 'rb') as f:
        return pickle.load(f)

